import{_ as i,o as s,c as p,am as r,bj as e,bk as l,bl as t,bm as n,bn as o,bo as h,bp as m,bq as d,br as g,bs as c,bt as b,bu as _,bv as u,bw as k,bx as A,by as I,bz as f,bA as w,bB as P,bC as x,bD as E}from"./chunks/framework.yzuB8YhR.js";const V=JSON.parse('{"title":"AI 智能体平台","description":"","frontmatter":{},"headers":[],"relativePath":"AI/Vibe Coding/06.AI 智能体平台.md","filePath":"AI/Vibe Coding/06.AI 智能体平台.md","lastUpdated":1776190046000}'),C={name:"AI/Vibe Coding/06.AI 智能体平台.md"};function F(M,a,T,v,y,q){return s(),p("div",null,[...a[0]||(a[0]=[r('<h1 id="ai-智能体平台" tabindex="-1">AI 智能体平台 <a class="header-anchor" href="#ai-智能体平台" aria-label="Permalink to “AI 智能体平台”">​</a></h1><h2 id="一、什么是-ai-智能体平台" tabindex="-1">一、什么是 AI 智能体平台？ <a class="header-anchor" href="#一、什么是-ai-智能体平台" aria-label="Permalink to “一、什么是 AI 智能体平台？”">​</a></h2><p>在讲 AI 智能体平台之前，我先帮大家理清几个容易混淆的概念：</p><p>1）零代码平台（Bolt.new、Lovable、秒哒）：一句话生成完整项目，适合快速做网站和应用。</p><p>你说一句话，AI 生成代码，你预览效果，满意就部署。整个过程可能只需要几分钟。</p><p>2）AI 应用开发平台（Dify、Coze、百炼）：可视化配置 AI 应用，适合做智能客服、知识库问答等 AI 应用。</p><p>你通过拖拽的方式配置工作流，设置提示词和知识库，不需要写代码。</p><p>3）AI 智能体平台（Flowith、Manus）：AI 自主规划和执行复杂任务，可以持续运行几个小时甚至几天。</p><p>你只需要描述目标，AI 会自己规划步骤、调用工具、执行任务，直到完成为止。</p><p>简单来说，<strong>AI 智能体平台就是让 AI 当项目经理，你只需要告诉它目标，它会自己规划和执行。</strong></p><h2 id="二、flowith-无限执行的-ai-智能体" tabindex="-1">二、Flowith：无限执行的 AI 智能体 <a class="header-anchor" href="#二、flowith-无限执行的-ai-智能体" aria-label="Permalink to “二、Flowith：无限执行的 AI 智能体”">​</a></h2><p><a href="https://flowith.io" target="_blank" rel="noreferrer">Flowith</a> 是目前最火的 AI 智能体平台之一，被称为&quot;世界上第一款无限的 AI 智能体&quot;（也可能是自称）。</p><p>什么叫&quot;无限&quot;？</p><p>如果我们把 AI 智能体想象成人类，有的人拿到任务后，觉得太复杂或者遇到困难就放弃了；而有的人哪怕废寝忘食、拼了一辈子，也要坚持完成任务。</p><p>Flowith 便是后者，<strong>无限的步骤、无限的上下文、无限的工具</strong>，使得它能够持续不断地自主执行任务，直到完成才罢休。</p><p><img src="'+e+'" alt="img"></p><h3 id="_2-1-怎么使用-flowith" tabindex="-1">2.1 怎么使用 Flowith？ <a class="header-anchor" href="#_2-1-怎么使用-flowith" aria-label="Permalink to “2.1 怎么使用 Flowith？”">​</a></h3><p>让我用几个实际例子来演示 Flowith 的强大能力。</p><h4 id="_2-1-1-生成复杂大型网站" tabindex="-1">2.1.1 生成复杂大型网站 <a class="header-anchor" href="#_2-1-1-生成复杂大型网站" aria-label="Permalink to “2.1.1 生成复杂大型网站”">​</a></h4><p>进入 <a href="https://flowith.io" target="_blank" rel="noreferrer">Flowith 主页</a>，看到了熟悉的 AI 对话页面。这是 Flowith 的基础功能，可以生成文本、图片、视频，利用联网搜索工具和自定义知识库来丰富回答的内容。</p><p><img src="'+l+'" alt="img"></p><p>我比较喜欢的是 <strong>比较模式</strong> 这个功能，可以选择各种主流大模型，快速对比同一个提示词的作答效果：</p><p><img src="'+t+'" alt="img"></p><p>下面让我们开启 Flowith 的 <strong>Agent 模式</strong>，也就是能够在云端自主规划任务、调用工具分步骤完成任务的超级智能体。并且开启 <strong>无限模式</strong>，让它一直工作直到完成任务。</p><img src="'+n+`" alt="img"><p>输入提示词：</p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">帮我生成一个复杂的企业级前端网站 - 低代码生成工具。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">至少有 20 个页面，并且确保所有的核心功能都完整可用。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>执行后，我们会进入到 <strong>工作流画布页面</strong>，可以看到，AI 首先为整个任务规划出了非常多的步骤。比如要制作网站，需要先写详细的架构设计文档、然后构建基础 UI 框架、再依次开发各个页面。</p><p><img src="`+o+'" alt="img"></p><p>这就是 AI 智能体能够自主执行复杂任务的原理。虽然没办法一次性完成大任务，那就先把任务分解成若干小任务，然后逐个完成并总结最终的结果。</p><p><img src="'+h+'" alt="img"></p><p>AI 会自主选择合适的工具来完成任务，比如生成网站并部署到云端服务器上，让我们可以实时查看每一步生成的网站效果：</p><p><img src="'+m+'" alt="img"></p><p>经过了漫长的等待，大概 2 个小时左右，整个网站终于生成完成。我之前在 Cursor 中使用智能体，从来没有自主执行过这么长的时间。</p><p>让我们看看生成的文件。首先生成的文档非常齐全，什么测试报告、发布确认文档、系统维护指南、测试计划、总结报告，应有尽有。</p><p><img src="'+d+'" alt="img"></p><p>再看看生成的项目代码，页面文件还算完整，生成了 5000 多行代码，属于中小型项目的规模。</p><p><img src="'+g+'" alt="img"></p><p>运行下网站看看效果。估计是用的国外大模型，生成的网站纯英文，页面有模有样，符合低代码平台的功能和设计。</p><p><img src="'+c+'" alt="img"></p><p>但是由于缺少后端以及示例数据，很多页面的功能是没有办法验证的，效果看起来也一般。</p><h4 id="_2-1-2-生成几十页-ppt" tabindex="-1">2.1.2 生成几十页 PPT <a class="header-anchor" href="#_2-1-2-生成几十页-ppt" aria-label="Permalink to “2.1.2 生成几十页 PPT”">​</a></h4><p>下面我们再来搞一个更复杂的任务，生成一个至少有 50 页的 PPT：</p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">帮我生成一个 PPT，用于从全方面介绍程序员鱼皮，至少 50 页。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这次的 AI 智能体显然更聪明，先同时调用了多个网页搜索工具，从不同的来源搜索到信息，然后再进行整合：</p><p><img src="'+b+'" alt="img"></p><p>AI 在给 PPT 准备图片素材时也很聪明，不仅从网络上搜索到了图片，而且还调用其他的 AI 绘图大模型并行生成了多张配图。实话说，这个小卡片的效果确实惊艳到我了。</p><p><img src="'+_+'" alt="img"></p><p>有趣的是，我发现 AI 并不是&quot;死脑筋&quot;。在执行任务的过程中，它可能会根据情况重新规划步骤；有时还会主动询问用户的意见，能够让我们参与进来，指导 AI 更好地完成任务。</p><p><img src="'+u+'" alt="img"></p><p>不过任务的执行并非一帆风顺，有的时候会出现步骤执行失败的情况，不过 AI 会自动重试：</p><p><img src="'+k+'" alt="img"></p><p>但更严重的是任务卡死。比如我一直卡在使用浏览器运行工具这一步，这时就需要手动重新执行。不过仔细想想也挺合理，人类工作有时候也会摸鱼睡着了，这时就需要其他人把他叫醒。</p><p>经过一个多小时，AI 终于生成了一个可在线访问的 PPT 网页，甚至部署到了服务器上。我们可以直接查看浏览效果：</p><p><img src="'+A+'" alt="img"></p><p>有一说一，我感觉还挺不错的。虽然生成的不是标准的 PPT 格式，而是 HTML 网页代码，但是利用工具，也能直接转成 PPT 格式。</p><p><img src="'+I+`" alt="img"></p><h4 id="_2-1-3-生成自媒体图文" tabindex="-1">2.1.3 生成自媒体图文 <a class="header-anchor" href="#_2-1-3-生成自媒体图文" aria-label="Permalink to “2.1.3 生成自媒体图文”">​</a></h4><p>下面再让 AI 生成一篇自媒体图文：</p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">我是一位自媒体知识博主，请帮我生成一篇图文并茂的图文稿子。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">主题是【介绍程序员鱼皮的编程导航学习网站】</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>建议大家每隔一段时间来看看 AI 的工作进度，说不定有时 AI 会主动询问你的建议，你不回答就会一直卡在这里（当然也可以跳过）。</p><p><img src="`+f+'" alt="img"></p><p>大概过了 30 分钟，AI 完成了任务，生成了一个图文并茂的网站，效果还不错。</p><p><img src="'+w+'" alt="img"></p><p>不得不说，AI 真的很喜欢生成网站啊。这也提醒我们，如果想让 AI 更准确地完成复杂任务，就一定要把任务描述清楚（比如生成 Markdown 格式的图文）。</p><h3 id="_2-2-flowith-的优缺点" tabindex="-1">2.2 Flowith 的优缺点 <a class="header-anchor" href="#_2-2-flowith-的优缺点" aria-label="Permalink to “2.2 Flowith 的优缺点”">​</a></h3><p>Flowith 的优势很明显。首先是 <strong>无限执行能力</strong>，可以持续运行几个小时甚至几天，完成超级复杂的任务。而且 AI 的规划和自我修正能力很强，能够根据情况调整计划。</p><p>还有就是 <strong>并行执行能力</strong>，可以同时调用多个 AI 模型或工具，大大提高效率。而且支持云端部署，生成的网站可以直接在线访问。</p><p>当然也有一些局限。首先是 <strong>执行效率比较低</strong>，同样的任务，Cursor 可能 10 分钟就能完成，Flowith 可能需要 1-2 个小时。而且消耗的费用不太可控，长时间运行会消耗大量的 Token。</p><p>另外，定制修改能力一般。如果你想精确控制每一步，Flowith 可能不太适合。它更适合那种&quot;我不管过程，只要结果&quot;的场景。</p><p>价格上，Flowith 有免费版和付费版。免费版有使用限制，付费版根据使用量计费。</p><h2 id="三、manus-通用-ai-智能体" tabindex="-1">三、Manus：通用 AI 智能体 <a class="header-anchor" href="#三、manus-通用-ai-智能体" aria-label="Permalink to “三、Manus：通用 AI 智能体”">​</a></h2><p><a href="https://manus.im" target="_blank" rel="noreferrer">Manus</a> 是另一个非常火的 AI 智能体平台，刚出的时候直接爆火。</p><p>Manus 采用多模型协同机制，具备强大的工具调用能力，能在多个领域自动生成和执行任务。而且 Manus 的自主规划能力很强，能够独立思考和规划，确保任务的执行。</p><p><img src="'+P+'" alt="img"></p><p>比如在房产选购任务中，Manus 能分解为社区安全分析、预算计算、房源筛选等子任务，并通过代码智能体重构思考过程，确保透明可追溯。</p><h2 id="四、openmanus-开源版-manus" tabindex="-1">四、OpenManus：开源版 Manus <a class="header-anchor" href="#四、openmanus-开源版-manus" aria-label="Permalink to “四、OpenManus：开源版 Manus”">​</a></h2><p><a href="https://github.com/mannaandpoem/OpenManus" target="_blank" rel="noreferrer">OpenManus</a> 是 Manus 的开源版本，据说是由几个 00 后用 3 小时复刻出来的。</p><p><img src="'+x+'" alt="img"></p><p>虽然功能没有 Manus 那么完善，但基本的智能体能力都有。而且完全开源免费，可以自己部署和定制。</p><p>OpenManus 是一个模块化的开源智能体框架，适用于：</p><ul><li>研究原型验证</li><li>智能体编排实验</li><li>自动化工作流</li><li>将多模态/LLM 能力集成到现有系统</li></ul><p>如果你喜欢折腾，想深入了解 AI 智能体的实现原理，OpenManus 是个不错的选择。</p><p><img src="'+E+'" alt="img"></p><h2 id="五、ai-智能体平台实战建议" tabindex="-1">五、AI 智能体平台实战建议 <a class="header-anchor" href="#五、ai-智能体平台实战建议" aria-label="Permalink to “五、AI 智能体平台实战建议”">​</a></h2><p>如果你想尝试 AI 智能体平台，我有几个建议：</p><h3 id="_5-1-任务描述要清晰" tabindex="-1">5.1 任务描述要清晰 <a class="header-anchor" href="#_5-1-任务描述要清晰" aria-label="Permalink to “5.1 任务描述要清晰”">​</a></h3><p>虽然 AI 能自主规划，但你的任务描述越清晰，AI 的执行效果就越好。不要只说&quot;做一个网站&quot;，而是要说清楚：</p><ul><li>网站的类型（企业官网、博客、电商等）</li><li>核心功能（至少列出 3-5 个）</li><li>风格要求（简洁、现代、卡通等）</li><li>技术要求（如果有的话）</li></ul><h3 id="_5-2-要有耐心" tabindex="-1">5.2 要有耐心 <a class="header-anchor" href="#_5-2-要有耐心" aria-label="Permalink to “5.2 要有耐心”">​</a></h3><p>AI 智能体平台的执行时间比较长，可能需要几个小时。建议：</p><ul><li>选择一个不太忙的时间开始任务</li><li>定期查看进度，及时回复 AI 的询问</li><li>如果任务卡住了，手动重新执行</li></ul><h3 id="_5-3-控制成本" tabindex="-1">5.3 控制成本 <a class="header-anchor" href="#_5-3-控制成本" aria-label="Permalink to “5.3 控制成本”">​</a></h3><p>长时间运行会消耗大量的 Token，成本可能会比较高。建议：</p><ul><li>先用免费额度测试</li><li>明确任务范围，避免 AI 做太多不必要的事情</li><li>如果预算有限，可以选择用 Cursor 或者其他 AI 编程工具分步骤完成</li></ul><h3 id="_5-4-结合其他工具使用-按需" tabindex="-1">5.4 结合其他工具使用（按需） <a class="header-anchor" href="#_5-4-结合其他工具使用-按需" aria-label="Permalink to “5.4 结合其他工具使用（按需）”">​</a></h3><p>AI 智能体平台更适合生成基础内容，然后再用 Cursor 进行精修。比如：</p><ul><li>用 Flowith 生成大型网站的基础框架</li><li>导出代码到 Cursor 中</li><li>用 Cursor 进行细节优化和功能完善</li></ul><p>这样既能利用 Flowith 的自主执行能力，又能利用 Cursor 的精确控制能力。</p><h2 id="最后" tabindex="-1">最后 <a class="header-anchor" href="#最后" aria-label="Permalink to “最后”">​</a></h2><p>看到这里，相信你已经对 AI 智能体平台有了全面的了解。</p><p>我建议不要把它当成日常开发工具，而是当成一个特殊场景的补充工具。如果你需要生成大量内容又不想人工投入精力、或者想快速搭建一个大型项目的框架时，可以试试 Flowith 等 AI 智能体平台。</p><p>到这里，我们已经学习了零代码开发的各种工具。从快速生成项目的零代码平台，到能自主执行复杂任务的 AI 智能体平台，这些工具都不需要你写代码，就能做出功能强大的应用。</p><p>但如果你想更深入地学习编程，想要更精确地控制代码，那么 AI 代码编辑器会更适合你。</p>',104)])])}const S=i(C,[["render",F]]);export{V as __pageData,S as default};
